"use client";

import * as React from "react";
import { cn } from "@/lib/utils";

interface CharacterCounterProps {
  currentLength: number;
  maxLength: number;
  className?: string;
}

/**
 * CharacterCounter - A small utility component to display character usage against a limit.
 * 
 * Rules:
 * - 0-89%: Muted (neutral)
 * - 90-99%: Orange (warning)
 * - >=100%: Red (danger)
 */
export function CharacterCounter({
  currentLength,
  maxLength,
  className,
}: CharacterCounterProps) {
  const percentage = (currentLength / maxLength) * 100;

  const colorClass = cn(
    "text-muted-foreground", // Default discret status
    percentage >= 90 && percentage < 100 && "text-amber-500 font-medium", // Warning status
    percentage >= 100 && "text-destructive font-bold" // Danger status
  );

  return (
    <div className={cn("flex justify-end pt-1", className)}>
      <span className={cn("text-[10px] tabular-nums tracking-tight transition-colors duration-200", colorClass)}>
        {currentLength} <span className="opacity-50 mx-0.5">/</span> {maxLength}
      </span>
    </div>
  );
}
